141→// BuildCountQuery builds a COUNT(*) query with the same WHERE clauses as BuildQuery
142→// but without LIMIT / OFFSET. Used to compute the total result count.
143→func BuildCountQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
144→	clauses, args, err := buildWhere(reg, req.Filters)
145→	if err != nil {
146→		return "", nil, err
147→	}
148→
149→	q := "SELECT COUNT(*) FROM search_base.dataset_merged"
150→	if len(clauses) > 0 {
151→		q += " WHERE " + strings.Join(clauses, " AND ")
152→	}
153→
154→	return q, args, nil
155→}
