158→// BuildExportQuery builds a parameterised SELECT query for CSV export.
159→// It is similar to BuildQuery but has no offset and caps the limit to maxRows
160→// instead of MaxLimit.
161→func BuildExportQuery(reg *Registry, req SearchRequest, maxRows int) (sql string, args []any, err error) {
162→	clauses, args, err := buildWhere(reg, req.Filters)
163→	if err != nil {
164→		return "", nil, err
165→	}
166→
167→	argStart := len(args) + 1
168→
169→	// Always select 10 columns so Scan is uniform.
170→	distanceExpr := "NULL::double precision"
171→	myPriceExpr := "NULL::integer"
172→	blendExpr := "NULL::double precision"
173→
174→	if req.UserLocation != nil {
175→		distanceExpr = fmt.Sprintf(
176→			"ST_Distance(coordinates, ST_SetSRID(ST_MakePoint($%d, $%d), 4326)::geography) / 1609.344",
177→			argStart, argStart+1,
178→		)
179→		args = append(args, req.UserLocation.Longitude, req.UserLocation.Latitude)
180→		argStart += 2
181→
182→		if req.UserLocation.State != "" {
183→			myPriceExpr = fmt.Sprintf(
184→				"CASE WHEN state = $%d THEN (data #>> '{nces,tuition_in_state}')::integer "+
185→					"ELSE (data #>> '{nces,tuition_out_of_state}')::integer END",
186→				argStart,
187→			)
188→			args = append(args, req.UserLocation.State)
189→			argStart++
190→		}
191→	}
192→
193→	if req.Blend != nil {
194→		expr, berr := buildBlendExpression(reg, req.Blend)
195→		if berr != nil {
196→			return "", nil, berr
197→		}
198→		blendExpr = expr
199→	}
200→
201→	q := fmt.Sprintf(
202→		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
203→		distanceExpr, myPriceExpr, blendExpr,
204→	)
205→	if len(clauses) > 0 {
206→		q += " WHERE " + strings.Join(clauses, " AND ")
207→	}
208→
209→	if req.Blend != nil {
210→		q += " ORDER BY 10 ASC NULLS LAST"
211→	} else {
212→		orderBy, err := buildOrderBy(reg, req)
213→		if err != nil {
214→			return "", nil, err
215→		}
216→		q += orderBy
217→	}
218→
219→	limit := req.Limit
220→	if limit <= 0 {
221→		limit = DefaultLimit
222→	}
223→	if limit > maxRows {
224→		limit = maxRows
225→	}
226→	q += fmt.Sprintf(" LIMIT $%d", argStart)
227→	args = append(args, limit)
228→
229→	return q, args, nil
230→}
