232→// buildWhere resolves each FilterInput to a SQL clause, advancing the placeholder
233→// index across filters so that $N numbering is globally consistent within one query.
234→func buildWhere(reg *Registry, filters []FilterInput) (clauses []string, args []any, err error) {
235→	argStart := 1
236→	for _, fi := range filters {
237→		field, ok := reg.Lookup(fi.Field)
238→		if !ok {
239→			return nil, nil, fmt.Errorf("unknown field %q", fi.Field)
240→		}
241→		clause, fieldArgs, ferr := field.BuildSQL(fi.Value, argStart)
242→		if ferr != nil {
243→			return nil, nil, fmt.Errorf("field %q: %w", fi.Field, ferr)
244→		}
245→		clauses = append(clauses, clause)
246→		args = append(args, fieldArgs...)
247→		argStart += len(fieldArgs)
248→	}
249→	return clauses, args, nil
250→}
